import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.OsDJF_Ea.js";const h=JSON.parse('{"title":"Signal Flow","description":"","frontmatter":{},"headers":[],"relativePath":"guides/signal-flow.md","filePath":"guides/signal-flow.md"}'),r={name:"guides/signal-flow.md"};function s(i,e,l,g,c,d){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="signal-flow" tabindex="-1">Signal Flow <a class="header-anchor" href="#signal-flow" aria-label="Permalink to &quot;Signal Flow&quot;">​</a></h1><p>Understanding how signals move through a Smart Contact Mic patch is the key to building patches that work.</p><h2 id="two-signal-types" tabindex="-1">Two Signal Types <a class="header-anchor" href="#two-signal-types" aria-label="Permalink to &quot;Two Signal Types&quot;">​</a></h2><p>Every port on a module is either <strong>audio</strong> (green) or <strong>control</strong> (purple).</p><p><strong>Audio signals</strong> are processed at the full sample rate (44,100 times per second). These carry the sound itself -- oscillator waveforms, filtered audio, reverb tails.</p><p><strong>Control signals</strong> update at a lower rate and typically range from 0 to 1. These carry modulation -- LFO shapes, envelope curves, pot positions, button states.</p><h2 id="signal-direction" tabindex="-1">Signal Direction <a class="header-anchor" href="#signal-direction" aria-label="Permalink to &quot;Signal Direction&quot;">​</a></h2><p>Signals flow <strong>left to right</strong> through a patch:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Sources] -&gt; [Effects] -&gt; [Output]</span></span></code></pre></div><ul><li><strong>Sources</strong> generate signal: Oscillator, Noise, Sample Player, Stereo In</li><li><strong>Effects</strong> process signal: Filter, Delay, Reverb, VCA</li><li><strong>Output</strong> sends signal to hardware: Stereo Out</li></ul><p>Control modules can connect to any parameter input on any module, creating modulation.</p><h2 id="the-processing-order" tabindex="-1">The Processing Order <a class="header-anchor" href="#the-processing-order" aria-label="Permalink to &quot;The Processing Order&quot;">​</a></h2><p>The firmware automatically sorts modules into the correct processing order using topological sorting. You don&#39;t need to worry about placement on the canvas -- the engine figures out which module needs to run first based on the connections you&#39;ve made.</p><h2 id="mixing" tabindex="-1">Mixing <a class="header-anchor" href="#mixing" aria-label="Permalink to &quot;Mixing&quot;">​</a></h2><p>When multiple cables connect to the same input port, the signals are summed (added together). This is how you mix: connect several oscillators to a mixer, or layer multiple modulation sources on a single parameter.</p><h2 id="common-signal-chains" tabindex="-1">Common Signal Chains <a class="header-anchor" href="#common-signal-chains" aria-label="Permalink to &quot;Common Signal Chains&quot;">​</a></h2><p><strong>Basic voice:</strong> Oscillator -&gt; Filter -&gt; VCA -&gt; Stereo Out (with ADSR controlling VCA gain, and a Pot controlling filter cutoff)</p><p><strong>Delay send:</strong> Source -&gt; Stereo Mixer -&gt; Stereo Out (Mixer aux send -&gt; Delay -&gt; Mixer return)</p><p><strong>MIDI keyboard patch:</strong> MIDI In -&gt; Oscillator (note) + ADSR (gate) -&gt; Filter -&gt; VCA (ADSR) -&gt; Stereo Out</p>',19)])])}const u=t(r,[["render",s]]);export{h as __pageData,u as default};
